1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge case: empty
6	  it("empty item list quote → premium 5 G (processing fee only)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums per item type
15	  it.todo("quote for single sword → 105 G (100 base + 5 fee)");
16	  it.todo("quote for single amulet → 65 G (60 base + 5 fee)");
17	  it.todo("quote for single staff → 85 G (80 base + 5 fee)");
18	  it.todo("quote for single potion → 45 G (40 base + 5 fee)");
19	
20	  // Component rules
21	  it.todo("quote for 1 rune → 30 G (25 base + 5 fee)");
22	  it.todo("quote for 2 runes → 55 G (50 base + 5 fee)");
23	  it.todo("quote for 3 runes → 65 G (60 block + 5 fee)");
24	  it.todo("quote for 4 runes → 105 G (100 base, no block + 5 fee)");
25	  it.todo("quote for 7 runes → 180 G (175 base + 5 fee)");
26	
27	  // Alike clarification
28	  it.todo("quote for 2 runes + 1 moonstone → 80 G (75 base, no block + 5 fee)");
29	  it.todo("quote for 3 runes + 3 moonstones → 125 G (120 base, two blocks + 5 fee)");
30	
31	  // Cursed surcharge
32	  it.todo("cursed sword (steel, ench 3), newcomer → 165 G (100 + 50 curse + 10 first + 5 fee)");
33	
34	  // High enchantment surcharge
35	  it.todo("sword enchantment 5 (not cursed), newcomer → 145 G (100 + 30 high-ench + 10 first + 5 fee)");
36	  it.todo("sword enchantment 4 (not cursed), newcomer → 115 G (100 + 10 first + 5 fee, no high-ench)");
37	  it.todo("cursed sword enchantment 5, newcomer → 195 G (100 + 50 curse + 30 high-ench + 10 first + 5 fee)");
38	
39	  // Loyalty
40	  it.todo("loyalty discount applies at exactly 2 years (sword, no other modifiers, newcomer-first contract) → 95 G (100 - 20 loyalty + 10 first + 5 fee)");
41	
42	  // First insurance & follow-up
43	  it.todo("second contract for long-standing customer (3 yrs) with cursed sword ench 7 → 160 G");
44	
45	  // Modifier scope on multi-item policies
46	  it.todo("cursed sword + plain amulet, newcomer → policy base 160 + curse 50 + first 16 + fee 5 = 231 G");
47	
48	  // Rounding (premium up)
49	  it.todo("premium calculation 197.5 G → 198 G (rounded up)");
50	
51	  // CLAIM examples
52	  // Standard reimbursement
53	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
54	  it.todo("rune (insurance 250), damage 200 G → payout 100 G");
55	
56	  // Enchantment threshold vs dragon material
57	  it.todo("dragon sword ench 8, damage 1000 G → payout 400 G (high-ench wins)");
58	  it.todo("dragon sword ench 9, damage 1000 G → payout 400 G (50% then deductible)");
59	  it.todo("dragon sword ench 5, damage 800 G → payout 700 G (full minus deductible)");
60	  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (high-ench applies)");
61	
62	  // Multiple damages
63	  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 G (deductible per item)");
64	
65	  // Multiple items same type
66	  it.todo("two swords insured → insurance sum 2000, cap 4000");
67	  it.todo("two sword damages with two swords insured → both processed with own deductible");
68	  it.todo("two sword damages with only one sword insured → error (non-zero exit)");
69	
70	  // Cap exhaustion
71	  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
72	  it.todo("cursed sword premium with modifiers 165 G but cap still 2000 (based on unmodified insurance value)");
73	  it.todo("sword + 3 runes (block) → insurance sum 1750 (block discount doesn't affect insurance sum)");
74	  it.todo("sword (cap 2000): claim 1500 → payout 1400, remaining 600; next claim 1500 → payout 600, remaining 0");
75	
76	  // Rounding (payout down)
77	  it.todo("payout calculation 350.5 G → 350 G (rounded down)");
78	
79	  // Error cases
80	  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr, no results on stdout");
81	  it.todo("claim references item not in policy → CLI exits non-zero, error on stderr");
82	  it.todo("claim with negative damage amount → CLI exits non-zero, error on stderr");
83	});
